def sparkline_svg(values, height=40, width=100, color="var(--accent)"):
    if not values or len(values) < 2:
        return f'<svg viewBox="0 0 {width} {height}" preserveAspectRatio="none" style="width:100%;height:100%;"><polyline points="0,{height/2} {width},{height/2}" fill="none" stroke="var(--border)" stroke-width="1.5"/></svg>'
    mn, mx = min(values), max(values)
    if mx == mn: mx += 1
    pts = []
    x_max = len(values) - 1
    for i, v in enumerate(values):
        x = (i / x_max) * width
        y = height - ((v - mn) / (mx - mn) * height)
        y = max(2, min(height-2, y))
        pts.append(f"{x:.1f},{y:.1f}")
    return f'<svg viewBox="0 0 {width} {height}" preserveAspectRatio="none" style="width:100%;height:100%;"><polyline points="{" ".join(pts)}" fill="none" stroke="{color}" stroke-width="1.5" stroke-linejoin="round"/></svg>'

hist_wpm = [r["current_wpm"] for r in recent_readings]
hist_acc = [max(0, 100 - (r.get("typo_rate", 0)*100)) for r in recent_readings]
hist_rhy = [max(0, 10 - r.get("rhythm_variability", 0)*5) for r in recent_readings]
hist_foc = [max(0, min(10, r["current_wpm"]/10.0) - min(5, r.get("pause_count", 0)*0.5)) for r in recent_readings]

val_wpm = hist_wpm[-1] if hist_wpm else 0
val_acc = hist_acc[-1] if hist_acc else 100.0
val_rhy = hist_rhy[-1] if hist_rhy else 10.0
val_foc = hist_foc[-1] if hist_foc else 10.0

